from openai import OpenAI
import json, math

client = OpenAI(api_key="your-key", base_url="https://api.deepseek.com/v1")

weather_db = {"北京": {"temp": 22, "humidity": 45, "condition": "晴"},
              "上海": {"temp": 28, "humidity": 70, "condition": "多云"}}

tools = [{
    "type": "function",
    "function": {
        "name": "weather_query", "description": "查询指定城市的天气",
        "parameters": {"type": "object", "properties": {"city": {"type": "string"}}, "required": ["city"]}}},
    {"type": "function",
     "function": {
         "name": "calculator", "description": "执行数学计算",
         "parameters": {"type": "object", "properties": {"expression": {"type": "string"}}, "required": ["expression"]}}}
]

def handle_tool_call(name, args):
    if name == "weather_query":
        city = json.loads(args).get("city", "")
        return weather_db.get(city, {"error": "城市未找到"})
    elif name == "calculator":
        expr = json.loads(args).get("expression", "")
        return {"result": eval(expr, {"__builtins__": {}}, {"math": math, "sqrt": math.sqrt})}

messages = [{"role": "user", "content": "北京今天天气怎么样？再帮我算一下 sqrt(256) + 42"}]
response = client.chat.completions.create(
    model="deepseek-chat", messages=messages, tools=tools, tool_choice="auto")

msg = response.choices[0].message
while msg.tool_calls:
    messages.append(msg)
    for tc in msg.tool_calls:
        result = handle_tool_call(tc.function.name, tc.function.arguments)
        messages.append({"role": "tool", "tool_call_id": tc.id, "content": json.dumps(result, ensure_ascii=False)})
    response = client.chat.completions.create(model="deepseek-chat", messages=messages)
    msg = response.choices[0].message

print(f"最终回答：{msg.content}")
